import{_ as e,o as a,c as p,ai as o}from"./chunks/framework.BrKG6FPr.js";const m=JSON.parse('{"title":"F1 2024赛年观赛总结","description":"","frontmatter":{"title":"F1 2024赛年观赛总结","prev":{"text":"新年大扫除（除胶）","link":"/blog/posts/chujiao"}},"headers":[],"relativePath":"blog/posts/F1-2025-summary/index.md","filePath":"blog/posts/F1-2025-summary/index.md","lastUpdated":1775099357000}'),s={name:"blog/posts/F1-2025-summary/index.md"};function r(n,t,i,_,d,l){return a(),p("div",null,[...t[0]||(t[0]=[o('<h1 id="f1-2025赛年观赛总结" tabindex="-1">F1 2025赛年观赛总结 <a class="header-anchor" href="#f1-2025赛年观赛总结" aria-label="Permalink to &quot;F1 2025赛年观赛总结&quot;">​</a></h1><p>不知不觉已经来到了4月，我在2024年的观赛总结里说2024赛季是近几年来最精彩的赛季，没想到2025赛季犹有过之。不过也正是由于过于精彩，导致我今年观赛已经提不起多少兴趣了，这或许是因为新规，也或许是因为在经历了可以说是波澜壮阔的一年后的乏味。</p><p>无论如何，如你所见，我还是在这样一个时间点，写下了这篇2025赛年观赛总结，即使我深知以我匮乏的语言表达能力难以诉说去年围场的精彩。</p><p>车队方面，迈凯伦不出意外的拿下了车队总冠军，但木瓜规则实在是让人忍俊不禁，如果真的丢了车手总冠军，成全了维斯塔潘的神话，我想迈凯伦的车队策略一定是不容忽视的重要因素。</p><p>红牛梭哈2025，不得不说，梭哈是一种智慧，可以终究还是差了两分，另外时至4月，已经可以看出红牛去年的梭哈，确实对今年的开发影响巨大。</p><p>法拉利梭哈2026，还是那句话，梭哈是一种智慧，2025法拉利的挣扎还是换来了2026年的美好开局，当然，可惜有梅奔。</p><p>梅赛德斯奔驰的总体表现与2024年的表现具有高度一致性。</p><p>其他车队的情况我很难有什么记忆，在周冠宇失去正式席位之后，我对中游和下游集团的关注度大大降低，即使还有些记忆点，也是对于这些车队车手的。</p><p>车手方面，维斯塔潘离传奇一步之遥，诺里斯的冠军无人在意，皮亚还是缺点火候，拉塞尔稳到难有镜头，乐扣依旧破碎美男，老汉职业生涯滑铁卢疑似晚节不保，二本全年压着塞恩斯但到赛季末感觉已经有些压不动了。</p><p>新秀车手方面，劳森的上限肉眼可见，杜汉纯倒霉蛋且确实不太行，熊人压着奥康打谁也没想到，蚁人未来光明，哈甲尔也是未来光明但很难说今年红牛能拿出一辆好车给他。哦，还有克拉平托，这位更是纯菜且嘴臭。</p><p>2026赛季已经跑完3场了，总是提不起什么看的欲望，或者说我最近什么欲望都提不起来。不知道今年还会不会看F1，以及明年还会不会有2026赛年观赛总结。</p>',11)])])}const f=e(s,[["render",r]]);export{m as __pageData,f as default};
